(function() {
    // Track if we've already modified any YouTube players
    let modifiedPlayers = new Set();

    // Function to pause videos and prevent autoplay
    function pauseYouTubeVideos() {
        // Handle standard HTML5 video elements
        const videoElements = document.getElementsByTagName('video');
        for (let i = 0; i < videoElements.length; i++) {
            videoElements[i].pause();

            // Prevent autoplay by removing the attribute
            if (videoElements[i].hasAttribute('autoplay')) {
                videoElements[i].removeAttribute('autoplay');
            }

            // Add event listener to pause again if it tries to play automatically
            if (!videoElements[i].hasAttribute('data-autoplay-prevented')) {
                videoElements[i].setAttribute('data-autoplay-prevented', 'true');
                videoElements[i].addEventListener('play', function(event) {
                    // Only pause if it wasn't started by user interaction
                    if (!window.userInteracted) {
                        event.target.pause();
                    }
                }, true);
            }
        }

        // Handle YouTube iframes
        const iframes = document.getElementsByTagName('iframe');
        for (let i = 0; i < iframes.length; i++) {
            const iframe = iframes[i];
            // Check if it's a YouTube iframe
            if (iframe.src && iframe.src.includes('youtube.com/embed/')) {
                if (!modifiedPlayers.has(iframe)) {
                    // Modify the iframe src to disable autoplay
                    let src = iframe.src;
                    // Remove any existing autoplay parameter
                    src = src.replace(/(&|\?)autoplay=1/g, '');
                    // Add autoplay=0 if not already present
                    if (!src.includes('autoplay=0')) {
                        src += (src.includes('?') ? '&' : '?') + 'autoplay=0';
                    }
                    // Force playlist parameter to avoid related videos autoplay
                    if (!src.includes('playlist=')) {
                        const videoId = src.match(/embed\/([^?&]+)/);
                        if (videoId && videoId[1]) {
                            src += '&playlist=' + videoId[1];
                        }
                    }
                    iframe.src = src;
                    modifiedPlayers.add(iframe);
                }
            }
        }

        // Handle YouTube's JavaScript API if it's available
        if (window.YT && window.YT.Player) {
            // Override the playVideo method
            const originalPlayVideo = window.YT.Player.prototype.playVideo;
            if (originalPlayVideo && !window.YT.Player.prototype._playVideoOverridden) {
                window.YT.Player.prototype._playVideoOverridden = true;
                window.YT.Player.prototype.playVideo = function() {
                    // Only allow playback if user has interacted
                    if (window.userInteracted) {
                        originalPlayVideo.apply(this, arguments);
                    }
                };
            }
        }
    }

    // Track user interaction
    window.userInteracted = false;
    function setUserInteracted() {
        window.userInteracted = true;
    }

    // Add event listeners for user interaction
    document.addEventListener('click', setUserInteracted, true);
    document.addEventListener('touchstart', setUserInteracted, true);

    // Run immediately
    pauseYouTubeVideos();

    // Observe DOM changes to catch dynamically added videos
    if (window.MutationObserver) {
        const observer = new MutationObserver(function(mutations) {
            for (let i = 0; i < mutations.length; i++) {
                if (mutations[i].addedNodes.length > 0) {
                    window.userInteracted = false; // Reset user interaction state
                    break;
                }
            }
        });

        observer.observe(document.body, {
            childList: true,
            subtree: true
        });
    }
})();